WITH p AS (SELECT 5690000000023241 AS pid, 2026 AS yr, 4 AS mon), pm AS (SELECT u_ywzb, u_zrcbzb FROM v_jxzl_project_metrics WHERE project_id = (SELECT pid FROM p)), amt AS ( SELECT ts.id, ts.pid, ts.phid_pc, ts.seq, CASE WHEN ts.seq = '5' THEN (SELECT u_ywzb FROM pm) ELSE 0 END AS ywzb, CASE WHEN ts.seq = '5' THEN (SELECT u_zrcbzb FROM pm) ELSE 0 END AS zrcbzb, CASE WHEN ts.seq = '5' THEN COALESCE((SELECT SUM(u_ewzb) FROM v_jxzl_cont_pack_metrics WHERE phid_pc = ts.phid_pc),0) + COALESCE((SELECT ewzb FROM v_jxzl_lxcg_ewzb WHERE phid_pc = ts.phid_pc),0) WHEN ts.seq LIKE '5.%' AND POSITION('.' IN SUBSTR(ts.seq,3)) = 0 AND ts.seq != '5.999' THEN COALESCE((SELECT u_ewzb FROM v_jxzl_cont_pack_metrics WHERE cont_pack_id = ts.id AND phid_pc = ts.phid_pc),0) WHEN ts.seq LIKE '5.%.%' AND LENGTH(ts.seq)-LENGTH(REPLACE(ts.seq,'.','')) = 2 THEN COALESCE((SELECT u_ewzb FROM v_jxzl_sub_cont_pack_metrics WHERE sub_cont_pack_id = ts.id AND phid_pc = ts.phid_pc),0) WHEN ts.seq = '5.999' THEN COALESCE((SELECT ewzb FROM v_jxzl_lxcg_ewzb WHERE phid_pc = ts.phid_pc),0) ELSE 0 END AS ewzb, CASE WHEN ts.seq = '5' THEN COALESCE((SELECT SUM(u_htje) FROM v_jxzl_cont_pack_metrics WHERE phid_pc = ts.phid_pc),0) WHEN ts.seq LIKE '5.%' AND POSITION('.' IN SUBSTR(ts.seq,3)) = 0 AND ts.seq != '5.999' THEN COALESCE((SELECT SUM(u_htje) FROM v_jxzl_sub_cont_pack_metrics WHERE cont_pack_id = ts.id AND phid_pc = ts.phid_pc),0) WHEN ts.seq LIKE '5.%.%' AND LENGTH(ts.seq)-LENGTH(REPLACE(ts.seq,'.','')) = 2 THEN COALESCE((SELECT u_htje FROM v_jxzl_sub_cont_pack_metrics WHERE sub_cont_pack_id = ts.id AND phid_pc = ts.phid_pc),0) WHEN ts.seq LIKE '5.%.%.%' THEN (SELECT total_sum FROM v_jxzl_base WHERE cnt_m_phid = ts.id AND phid_pc = ts.phid_pc) ELSE 0 END AS htje, CASE WHEN ts.seq = '5' THEN (SELECT COALESCE(SUM(amt),0) FROM v_jxzl_settle_mon WHERE phid_pc = ts.phid_pc AND yr = p.yr AND mon = p.mon) + (SELECT COALESCE(amt,0) FROM v_jxzl_lxcg_mon WHERE phid_pc = ts.phid_pc AND yr = p.yr AND mon = p.mon) WHEN ts.seq LIKE '5.%' AND POSITION('.' IN SUBSTR(ts.seq,3)) = 0 AND ts.seq != '5.999' THEN (SELECT COALESCE(SUM(s.amt),0) FROM v_jxzl_settle_mon s JOIN v_jxzl_base b ON s.contract_id = b.cnt_m_phid AND s.phid_pc = b.phid_pc WHERE b.parent_pcpd_phid = ts.id AND b.phid_pc = ts.phid_pc AND s.yr = p.yr AND s.mon = p.mon) WHEN ts.seq LIKE '5.%.%' AND LENGTH(ts.seq)-LENGTH(REPLACE(ts.seq,'.','')) = 2 THEN (SELECT COALESCE(SUM(s.amt),0) FROM v_jxzl_settle_mon s JOIN v_jxzl_base b ON s.contract_id = b.cnt_m_phid AND s.phid_pc = b.phid_pc WHERE b.pcpd_phid = ts.id AND b.phid_pc = ts.phid_pc AND s.yr = p.yr AND s.mon = p.mon) WHEN ts.seq LIKE '5.%.%.%' THEN (SELECT COALESCE(amt,0) FROM v_jxzl_settle_mon WHERE contract_id = ts.id AND phid_pc = ts.phid_pc AND yr = p.yr AND mon = p.mon) WHEN ts.seq = '5.999' THEN (SELECT COALESCE(amt,0) FROM v_jxzl_lxcg_mon WHERE phid_pc = ts.phid_pc AND yr = p.yr AND mon = p.mon) ELSE 0 END AS bykd, 0 AS bnljkd, 0 AS kgljkd, 0 AS byysgck, 0 AS kgljysgck FROM v_jxzl_tree ts, p WHERE ts.phid_pc = p.pid ) SELECT ts.phid_pc, ts.id AS s_tree_id, ts.pid AS s_tree_pid, ts.seq AS s_tree_no, ts.htbh AS u_htbh, ts.name AS s_tree_name, a.ywzb, a.zrcbzb, a.ewzb, a.htje, a.htje AS yjjsz, a.bykd, a.bnljkd, a.kgljkd, a.byysgck, a.kgljysgck, 0 AS byssgck, 0 AS kgljssgck, '' AS htzt, p.yr AS tj_year, p.mon AS tj_mon FROM v_jxzl_tree ts JOIN amt a ON ts.id = a.id AND ts.phid_pc = a.phid_pc CROSS JOIN p WHERE ts.phid_pc = p.pid ORDER BY CASE WHEN ts.seq = '5' THEN 1 WHEN ts.seq = '5.999' THEN 999 ELSE 2 END, ts.seq;